mapper.select:
select s.*, m.name as movie_name, m.image as movie_image, c.name as cinema_name, c.address as cinema_address, h.name as hall_name, h.total_seats, (h.total_seats - (select count(*) from ticket_detail td join ticket t on td.ticket_id = t.id where t.schedule_id = s.id and t.status != 3)) as available_seats from schedule s left join movie m on s.movie_id = m.id left join cinema c on s.cinema_id = c.id left join hall h on s.hall_id = h.id
s.status = 1
and s.movie_id = #{movieId}
and s.cinema_id = #{cinemaId}
and s.show_date = #{showDate}
order by s.show_date, s.show_time
